import { useParams, useNavigate } from "react-router-dom";
import axios from 'axios';
import { useState, useEffect } from 'react';
import './modifierUtilisateur.css';

export default function ModifierUtilisateur() {
    const [user, setUser] = useState(null);
    const [username, setUsername] = useState('');
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [role, setRole] = useState('');
    const { id } = useParams();
    const navigate = useNavigate();
    const token = localStorage.getItem("token");

    const getUser = async () => {
        try {
            const res = await axios.get(`http://localhost:3001/users`, {
                headers: { Authorization: `Bearer ${token}` }
            });
            // Find the specific user by ID
            const foundUser = res.data.find(u => u._id === id);
            if (foundUser) {
                setUser(foundUser);
                setUsername(foundUser.username);
                setEmail(foundUser.email);
                setPassword(foundUser.password);
                setRole(foundUser.role);
            }
        } catch (error) {
            console.error('Error fetching user:', error);
        }
    };

    useEffect(() => {
        getUser();
    }, [id]);

    const updateUser = async (e) => {
        e.preventDefault();
        const updatedUser = {
            username: username,
            email: email,
            password: password,
            role: role
        };
        try {
            const res = await axios.put(`http://localhost:3001/update/${id}`, updatedUser, {
                headers: { Authorization: `Bearer ${token}` }
            });
            navigate('/AfficherUtilisateurs');
        } catch (error) {
            console.error('Error updating user:', error);
        }
    };

    if (!user) {
        return (
            <div className="loading-container">
                <div className="loading-spinner"></div>
                <p>Chargement des données utilisateur...</p>
            </div>
        );
    }

    return (
        <div className="edit-user-container">
            <div className="edit-user-card">
                <div className="card-header">
                    <h1>Modifier l'Utilisateur</h1>
                    <p>Modifiez les informations de l'utilisateur sélectionné</p>
                </div>

                <form onSubmit={updateUser} className="edit-user-form">
                    <div className="form-group">
                        <label htmlFor="username">Nom d'utilisateur</label>
                        <input
                            type="text"
                            id="username"
                            value={username}
                            onChange={(e) => setUsername(e.target.value)}
                            placeholder="Entrez le nom d'utilisateur"
                            required
                        />
                    </div>

                    <div className="form-group">
                        <label htmlFor="email">Adresse Email</label>
                        <input
                            type="email"
                            id="email"
                            value={email}
                            onChange={(e) => setEmail(e.target.value)}
                            placeholder="Entrez l'adresse email"
                            required
                        />
                    </div>

                    <div className="form-group">
                        <label htmlFor="password">Mot de passe</label>
                        <input
                            type="password"
                            id="password"
                            value={password}
                            onChange={(e) => setPassword(e.target.value)}
                            placeholder="Entrez le nouveau mot de passe"
                            required
                        />
                    </div>

                    <div className="form-group">
                        <label htmlFor="role">Rôle</label>
                        <select
                            id="role"
                            value={role}
                            onChange={(e) => setRole(e.target.value)}
                            required
                        >
                            <option value="" disabled>Choisissez un rôle</option>
                            <option value="admin">Administrateur</option>
                            <option value="student">Étudiant</option>
                        </select>
                    </div>

                    <div className="form-actions">
                        <button type="button" onClick={() => navigate('/AfficherUtilisateurs')} className="cancel-btn">
                            Annuler
                        </button>
                        <button type="submit" className="submit-btn">
                            💾 Sauvegarder les modifications
                        </button>
                    </div>
                </form>
            </div>
        </div>
    );
}
